class Solution:
    def isRationalEqual(self, s: str, t: str) -> bool:
        def convert(s):
            if '(' not in s:
                return float(s)
            else:
                integer_part, decimal_part = s.split('.')
                non_repeating_part, repeating_part = decimal_part.split('(')
                repeating_part = repeating_part[:-1]
                decimal = float(integer_part + '.' + non_repeating_part)
                repeating_decimal = float('0.' + repeating_part)
                return decimal + repeating_decimal / (10 ** len(non_repeating_part) * (10 ** len(repeating_part) - 1))

        return convert(s) == convert(t)
```
